    private static Random random = new Random(new Date().getTime());

    public static String genOneChineseChars() {
        String str = null;
        int highPos = 176 + Math.abs(random.nextInt(39));
        int lowPos = 161 + Math.abs(random.nextInt(93));
        byte[] b = new byte[]{Integer.valueOf(highPos).byteValue(), Integer.valueOf(lowPos).byteValue()};
        try {
            str = new String(b, "GB2312");
        }
        catch (UnsupportedEncodingException e) {
            LogUtils.error(e);
        }
        return str;
    }

    public static String genFixedLengthChineseChars(int length) {
        Object str = "";
        for (int i = length; i > 0; --i) {
            str = (String)str + ChineseCharUtils.genOneChineseChars();
        }
        return str.toString();
    }

    public static String genRandomLengthChineseChars(int start, int end) {
        Object str = "";
        int length = random.nextInt(end + 1);
        if (length < start) {
            str = ChineseCharUtils.genRandomLengthChineseChars(start, end);
        } else {
            for (int i = 0; i < length; ++i) {
                str = (String)str + ChineseCharUtils.genOneChineseChars();
            }
        }
        return str.toString();
    }

    public static char getOneOddChar() {
        return ODD_CHINESE_CHARS.charAt(random.nextInt(ODD_CHINESE_CHARS.length()));
    }
